import logging
import azure.functions as func
import json
import os
from azure.identity import DefaultAzureCredential
from azure.keyvault.secrets import SecretClient

# Initialize logging
logging.basicConfig(level=logging.INFO)

# Initialize Key Vault client
key_vault_url = os.environ["KEY_VAULT_URL"]
credential = DefaultAzureCredential()
secret_client = SecretClient(vault_url=key_vault_url, credential=credential)

# CORS configuration
def set_cors_headers(response):
    response.headers['Access-Control-Allow-Origin'] = '*'
    response.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
    response.headers['Access-Control-Allow-Headers'] = 'Content-Type'
    return response

# Validate input function
def validate_input(data):
    if not isinstance(data, dict) or 'name' not in data:
        raise ValueError("Invalid input: 'name' key is required.")

# Main function
def main(req: func.HttpRequest) -> func.HttpResponse:
    logging.info('Processing request.')

    if req.method == "OPTIONS":
        return set_cors_headers(func.HttpResponse(status_code=204))

    try:
        req_body = req.get_json()
        validate_input(req_body)

        # Example of retrieving a secret securely
        secret_name = "MySecret"
        secret_value = secret_client.get_secret(secret_name).value

        response_data = {
            "message": f"Hello, {req_body['name']}!",
            "secret": secret_value  # Do not expose sensitive data in production
        }

        response = func.HttpResponse(
            json.dumps(response_data),
            status_code=200,
            mimetype="application/json"
        )
        return set_cors_headers(response)

    except ValueError as e:
        return set_cors_headers(func.HttpResponse(
            json.dumps({"error": str(e)}),
            status_code=400,
            mimetype="application/json"
        ))
    except Exception as e:
        logging.error(f"Error: {str(e)}")
        return set_cors_headers(func.HttpResponse(
            json.dumps({"error": "An error occurred."}),
            status_code=500,
            mimetype="application/json"
        ))